5. /// <summary>
6. /// Represents a data size with support for bits, bytes, kilobytes, megabytes,
7. /// gigabytes, and terabytes. Provides formatting, arithmetic, and comparison operations.
8. /// </summary>
9. public readonly struct DataSize :
10.     IComparable<DataSize>,
11.     IEquatable<DataSize>,
12.     IComparable,
13.     IFormattable
14. {
15.     public const string BitSymbol = "b";
16.     public const string ByteSymbol = "B";
17.     public const string KilobyteSymbol = "KB";
18.     public const string MegabyteSymbol = "MB";
19.     public const string GigabyteSymbol = "GB";
20.     public const string TerabyteSymbol = "TB";
21. 
22.     public const long BitsInByte = 8;
23.     public const long BytesInKilobyte = 1024;
24.     public const long BytesInMegabyte = 1_048_576;
25.     public const long BytesInGigabyte = 1_073_741_824;
26.     public const long BytesInTerabyte = 1_099_511_627_776;
27. 
28.     /// <summary>
29.     /// Gets the smallest possible <see cref="DataSize"/> value.
30.     /// </summary>
31.     public static readonly DataSize MinValue = FromBits(long.MinValue);
32. 
33.     /// <summary>
34.     /// Gets the largest possible <see cref="DataSize"/> value.
35.     /// </summary>
36.     public static readonly DataSize MaxValue = FromBits(long.MaxValue);
37. 
38.     // Single field: 8 bytes instead of 48 — eliminates copy overhead for this value type.
39.     private readonly long _bits;
40. 
41.     /// <summary>
42.     /// Initializes a new instance of the <see cref="DataSize"/> struct with the specified number of bytes.
43.     /// </summary>
44.     /// <param name="byteSize">The size in bytes.</param>
45.     public DataSize(double byteSize)
46.     {
47.         _bits = (long)Math.Ceiling(byteSize * BitsInByte);
48.     }
49. 
50.     private DataSize(long bits)
51.     {
52.         _bits = bits;
53.     }
54. 
55.     /// <summary>Gets the number of bits.</summary>
56.     public long Bits => _bits;
57. 
58.     /// <summary>Gets the number of bytes.</summary>
59.     public double Bytes => (double)_bits / BitsInByte;
60. 
61.     /// <summary>Gets the number of kilobytes.</summary>
62.     public double Kilobytes => (double)_bits / (BitsInByte * BytesInKilobyte);
63. 
64.     /// <summary>Gets the number of megabytes.</summary>
65.     public double Megabytes => (double)_bits / (BitsInByte * BytesInMegabyte);
66. 
67.     /// <summary>Gets the number of gigabytes.</summary>
68.     public double Gigabytes => (double)_bits / (BitsInByte * BytesInGigabyte);
69. 
70.     /// <summary>Gets the number of terabytes.</summary>
71.     public double Terabytes => (double)_bits / (BitsInByte * BytesInTerabyte);
72. 
73.     /// <summary>
74.     /// Gets the largest whole number value and its corresponding unit symbol.
75.     /// </summary>
76.     public string LargestWholeNumberSymbol => GetLargestWholeNumber().Symbol;
77. 
78.     /// <summary>
79.     /// Gets the value in the largest whole number unit.
80.     /// </summary>
81.     public double LargestWholeNumberValue => GetLargestWholeNumber().Value;
82. 
83.     private (double Value, string Symbol) GetLargestWholeNumber()
84.     {
85.         var tb = Terabytes;
86.         if (Math.Abs(tb) >= 1) return (tb, TerabyteSymbol);
87. 
88.         var gb = Gigabytes;
89.         if (Math.Abs(gb) >= 1) return (gb, GigabyteSymbol);
90. 
91.         var mb = Megabytes;
92.         if (Math.Abs(mb) >= 1) return (mb, MegabyteSymbol);
93. 
94.         var kb = Kilobytes;
95.         if (Math.Abs(kb) >= 1) return (kb, KilobyteSymbol);
96. 
97.         var bytes = Bytes;
98.         if (Math.Abs(bytes) >= 1) return (bytes, ByteSymbol);
99. 
100.         return (_bits, BitSymbol);
101.     }
